8342 static SelectPatternResult matchMinMax(CmpInst::Predicate Pred,
8343                                        Value *CmpLHS, Value *CmpRHS,
8344                                        Value *TrueVal, Value *FalseVal,
8345                                        Value *&LHS, Value *&RHS,
8346                                        unsigned Depth) {
8347   // Assume success. If there's no match, callers should not use these anyway.
8348   LHS = TrueVal;
8349   RHS = FalseVal;
8350 
8351   SelectPatternResult SPR = matchClamp(Pred, CmpLHS, CmpRHS, TrueVal, FalseVal);
8352   if (SPR.Flavor != SelectPatternFlavor::SPF_UNKNOWN)
8353     return SPR;
8354 
8355   SPR = matchMinMaxOfMinMax(Pred, CmpLHS, CmpRHS, TrueVal, FalseVal, Depth);
8356   if (SPR.Flavor != SelectPatternFlavor::SPF_UNKNOWN)
8357     return SPR;
8358 
8359   // Look through 'not' ops to find disguised min/max.
8360   // (X > Y) ? ~X : ~Y ==> (~X < ~Y) ? ~X : ~Y ==> MIN(~X, ~Y)
8361   // (X < Y) ? ~X : ~Y ==> (~X > ~Y) ? ~X : ~Y ==> MAX(~X, ~Y)
8362   if (CmpLHS == getNotValue(TrueVal) && CmpRHS == getNotValue(FalseVal)) {
8363     switch (Pred) {
8364     case CmpInst::ICMP_SGT: return {SPF_SMIN, SPNB_NA, false};
8365     case CmpInst::ICMP_SLT: return {SPF_SMAX, SPNB_NA, false};
8366     case CmpInst::ICMP_UGT: return {SPF_UMIN, SPNB_NA, false};
8367     case CmpInst::ICMP_ULT: return {SPF_UMAX, SPNB_NA, false};
8368     default: break;
8369     }
8370   }
8371 
8372   // (X > Y) ? ~Y : ~X ==> (~X < ~Y) ? ~Y : ~X ==> MAX(~Y, ~X)
8373   // (X < Y) ? ~Y : ~X ==> (~X > ~Y) ? ~Y : ~X ==> MIN(~Y, ~X)
8374   if (CmpLHS == getNotValue(FalseVal) && CmpRHS == getNotValue(TrueVal)) {
8375     switch (Pred) {
8376     case CmpInst::ICMP_SGT: return {SPF_SMAX, SPNB_NA, false};
8377     case CmpInst::ICMP_SLT: return {SPF_SMIN, SPNB_NA, false};
8378     case CmpInst::ICMP_UGT: return {SPF_UMAX, SPNB_NA, false};
8379     case CmpInst::ICMP_ULT: return {SPF_UMIN, SPNB_NA, false};
8380     default: break;
8381     }
8382   }
8383 
8384   if (Pred != CmpInst::ICMP_SGT && Pred != CmpInst::ICMP_SLT)
8385     return {SPF_UNKNOWN, SPNB_NA, false};
8386 
8387   const APInt *C1;
8388   if (!match(CmpRHS, m_APInt(C1)))
8389     return {SPF_UNKNOWN, SPNB_NA, false};
8390 
8391   // An unsigned min/max can be written with a signed compare.
8392   const APInt *C2;
8393   if ((CmpLHS == TrueVal && match(FalseVal, m_APInt(C2))) ||
8394       (CmpLHS == FalseVal && match(TrueVal, m_APInt(C2)))) {
8395     // Is the sign bit set?
8396     // (X <s 0) ? X : MAXVAL ==> (X >u MAXVAL) ? X : MAXVAL ==> UMAX
8397     // (X <s 0) ? MAXVAL : X ==> (X >u MAXVAL) ? MAXVAL : X ==> UMIN
8398     if (Pred == CmpInst::ICMP_SLT && C1->isZero() && C2->isMaxSignedValue())
8399       return {CmpLHS == TrueVal ? SPF_UMAX : SPF_UMIN, SPNB_NA, false};
8400 
8401     // Is the sign bit clear?
8402     // (X >s -1) ? MINVAL : X ==> (X <u MINVAL) ? MINVAL : X ==> UMAX
8403     // (X >s -1) ? X : MINVAL ==> (X <u MINVAL) ? X : MINVAL ==> UMIN
8404     if (Pred == CmpInst::ICMP_SGT && C1->isAllOnes() && C2->isMinSignedValue())
8405       return {CmpLHS == FalseVal ? SPF_UMAX : SPF_UMIN, SPNB_NA, false};
8406   }
8407 
8408   return {SPF_UNKNOWN, SPNB_NA, false};
8409 }
