8411 bool llvm::isKnownNegation(const Value *X, const Value *Y, bool NeedNSW,
8412                            bool AllowPoison) {
8413   assert(X && Y && "Invalid operand");
8414 
8415   auto IsNegationOf = [&](const Value *X, const Value *Y) {
8416     if (!match(X, m_Neg(m_Specific(Y))))
8417       return false;
8418 
8419     auto *BO = cast<BinaryOperator>(X);
8420     if (NeedNSW && !BO->hasNoSignedWrap())
8421       return false;
8422 
8423     auto *Zero = cast<Constant>(BO->getOperand(0));
8424     if (!AllowPoison && !Zero->isNullValue())
8425       return false;
8426 
8427     return true;
8428   };
8429 
8430   // X = -Y or Y = -X
8431   if (IsNegationOf(X, Y) || IsNegationOf(Y, X))
8432     return true;
8433 
8434   // X = sub (A, B), Y = sub (B, A) || X = sub nsw (A, B), Y = sub nsw (B, A)
8435   Value *A, *B;
8436   return (!NeedNSW && (match(X, m_Sub(m_Value(A), m_Value(B))) &&
8437                         match(Y, m_Sub(m_Specific(B), m_Specific(A))))) ||
8438          (NeedNSW && (match(X, m_NSWSub(m_Value(A), m_Value(B))) &&
8439                        match(Y, m_NSWSub(m_Specific(B), m_Specific(A)))));
8440 }
