8442 bool llvm::isKnownInversion(const Value *X, const Value *Y) {
8443   // Handle X = icmp pred A, B, Y = icmp pred A, C.
8444   Value *A, *B, *C;
8445   CmpPredicate Pred1, Pred2;
8446   if (!match(X, m_ICmp(Pred1, m_Value(A), m_Value(B))) ||
8447       !match(Y, m_c_ICmp(Pred2, m_Specific(A), m_Value(C))))
8448     return false;
8449 
8450   // They must both have samesign flag or not.
8451   if (Pred1.hasSameSign() != Pred2.hasSameSign())
8452     return false;
8453 
8454   if (B == C)
8455     return Pred1 == ICmpInst::getInversePredicate(Pred2);
8456 
8457   // Try to infer the relationship from constant ranges.
8458   const APInt *RHSC1, *RHSC2;
8459   if (!match(B, m_APInt(RHSC1)) || !match(C, m_APInt(RHSC2)))
8460     return false;
8461 
8462   // Sign bits of two RHSCs should match.
8463   if (Pred1.hasSameSign() && RHSC1->isNonNegative() != RHSC2->isNonNegative())
8464     return false;
8465 
8466   const auto CR1 = ConstantRange::makeExactICmpRegion(Pred1, *RHSC1);
8467   const auto CR2 = ConstantRange::makeExactICmpRegion(Pred2, *RHSC2);
8468 
8469   return CR1.inverse() == CR2;
8470 }
