8577 static SelectPatternResult matchSelectPattern(CmpInst::Predicate Pred,
8578                                               FastMathFlags FMF,
8579                                               Value *CmpLHS, Value *CmpRHS,
8580                                               Value *TrueVal, Value *FalseVal,
8581                                               Value *&LHS, Value *&RHS,
8582                                               unsigned Depth) {
