8177         *FC1 < *FC2)
8178       return {SPF_FMAXNUM, SPNB_RETURNS_ANY, false};
8179     break;
8180   case CmpInst::FCMP_OGT:
8181   case CmpInst::FCMP_OGE:
8182   case CmpInst::FCMP_UGT:
8183   case CmpInst::FCMP_UGE:
