8197 static SelectPatternResult matchClamp(CmpInst::Predicate Pred,
8198                                       Value *CmpLHS, Value *CmpRHS,
8199                                       Value *TrueVal, Value *FalseVal) {
8200   // Swap the select operands and predicate to match the patterns below.
8201   if (CmpRHS != TrueVal) {
8202     Pred = ICmpInst::getSwappedPredicate(Pred);
8203     std::swap(TrueVal, FalseVal);
8204   }
8205   const APInt *C1;
8206   if (CmpRHS == TrueVal && match(CmpRHS, m_APInt(C1))) {
8207     const APInt *C2;
8208     // (X <s C1) ? C1 : SMIN(X, C2) ==> SMAX(SMIN(X, C2), C1)
8209     if (match(FalseVal, m_SMin(m_Specific(CmpLHS), m_APInt(C2))) &&
8210         C1->slt(*C2) && Pred == CmpInst::ICMP_SLT)
8211       return {SPF_SMAX, SPNB_NA, false};
8212 
8213     // (X >s C1) ? C1 : SMAX(X, C2) ==> SMIN(SMAX(X, C2), C1)
8214     if (match(FalseVal, m_SMax(m_Specific(CmpLHS), m_APInt(C2))) &&
8215         C1->sgt(*C2) && Pred == CmpInst::ICMP_SGT)
8216       return {SPF_SMIN, SPNB_NA, false};
8217 
8218     // (X <u C1) ? C1 : UMIN(X, C2) ==> UMAX(UMIN(X, C2), C1)
8219     if (match(FalseVal, m_UMin(m_Specific(CmpLHS), m_APInt(C2))) &&
8220         C1->ult(*C2) && Pred == CmpInst::ICMP_ULT)
8221       return {SPF_UMAX, SPNB_NA, false};
8222 
8223     // (X >u C1) ? C1 : UMAX(X, C2) ==> UMIN(UMAX(X, C2), C1)
8224     if (match(FalseVal, m_UMax(m_Specific(CmpLHS), m_APInt(C2))) &&
8225         C1->ugt(*C2) && Pred == CmpInst::ICMP_UGT)
8226       return {SPF_UMIN, SPNB_NA, false};
8227   }
8228   return {SPF_UNKNOWN, SPNB_NA, false};
